    setResponseStatus: (responseStatus) =>
      set((state) => ({
        rescue: {
          ...state.rescue,
          responseStatus,
        },
      })),

    setError: (error) =>
      set((state) => ({
        rescue: {
          ...state.rescue,
          error,
        },
      })),

    reset: () =>
      set({
        rescue: initialRescueState,
      }),
  },
});

